// frontend/src/components/Dashboard.js
import React, { useEffect, useState } from "react";
import axios from "axios";
import { Pie, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";

ChartJS.register(
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title
);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    axios.get("/api/dashboard-stats")
      .then(res => setStats(res.data))
      .catch(err => console.error("Error fetching dashboard stats", err));
  }, []);

  if (!stats) return <p>Loading Dashboard...</p>;

  // Pie Chart Data: Free vs Occupied
  const pieData = {
    labels: ["Free Rooms", "Occupied Rooms"],
    datasets: [
      {
        label: "Room Status",
        data: [stats.pieChart.free, stats.pieChart.occupied],
        backgroundColor: ["#4caf50", "#f44336"],
        hoverOffset: 6,
      },
    ],
  };

  // Bar Chart Data: Free rooms across days
  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms per Day",
        data: Object.values(stats.barChart),
        backgroundColor: "#2196f3",
      },
    ],
  };

  return (
    <div style={{ padding: "2rem" }}>
      <h1>Dashboard</h1>

      <div style={{ display: "flex", gap: "2rem", flexWrap: "wrap" }}>
        <div style={{ flex: 1, minWidth: "300px" }}>
          <h3>Room Utilization</h3>
          <Pie data={pieData} />
        </div>

        <div style={{ flex: 2, minWidth: "300px" }}>
          <h3>Free Rooms (Mon–Fri)</h3>
          <Bar data={barData} />
        </div>
      </div>

      <div style={{ marginTop: "2rem" }}>
        <h3>Resources Summary</h3>
        <ul>
          <li>Total Rooms: {stats.resourceSummary.totalRooms}</li>
          <li>Labs: {stats.resourceSummary.labs}</li>
          <li>Projector-equipped Rooms: {stats.resourceSummary.projectors}</li>
          <li>General Classrooms: {stats.resourceSummary.classrooms}</li>
        </ul>
      </div>
    </div>
  );
};

export default Dashboard;
